                                tag.Tag,
                                t.repoURL,
                                err,
                        )
                }
                if t.MatchesPaths(diffPaths) {
                        filteredTags = append(filteredTags, tag)
                }
                if len(filteredTags) >= t.discoveryLimit {
                        break
                }
        }
        return filteredTags, nil
}

